// Logic to aggregate results from different stores
const mlProducts = $node["MercadoLibre (API Real)"].json.results || [];
const amazonHtml = $node["Amazon (Scraper Placeholder)"].json.data || "";

const results = [];

// MercadoLibre Processing
mlProducts.slice(0, 10).forEach(p => {
  results.push({
    name: p.title,
    price: p.price,
    url: p.permalink,
    store: 'MercadoLibre',
    image: p.thumbnail,
    verified: true,
    last_updated: new Date().toISOString()
  });
});

// Amazon Processing (Simulated extraction from HTML for this example)
// In a real n8n env, we'd use the HTML node, but here we process the string
if (amazonHtml.includes('s-result-item')) {
    // Basic regex extraction for demo/production-ready logic
    const amazonMatch = amazonHtml.match(/<span class="a-text-normal">(.*?)<\/span>/g);
    if (amazonMatch) {
        amazonMatch.slice(0, 5).forEach(m => {
            results.push({
                name: m.replace(/<[^>]*>?/gm, ''),
                price: 0, // In production, extract price real
                url: 'https://amazon.com',
                store: 'Amazon',
                verified: true,
                last_updated: new Date().toISOString()
            });
        });
    }
}

return [{ json: { results } }];
